a_4 - a_3 &= a_1 r^3 - a_1 r^2.
\end{align*}
\]
We can now plug in 576 for $a_5 - a_4$ and 9 for $a_2 - a_1$ to get \[
\begin{align*}
a_1 r^4 - a_1 r^3 &= 576, \\
a_1 r^3 - a_1 r^2 &= 9.
\end{align*}
\]
Simplifying, we have \[
\begin{align*}
a_1 r^3(r - 1) &= 576, \\
a_1 r^2(r - 1) &= 9.
\end{align*}
\]
Cancelling, we see that \[
\begin{align*}
\frac{576}{9} &= 64 = \frac{a_1 r^3(r - 1)}{a_1 r^2(r - 1)} = r.
\end{align*}
